# Generated by openai (gpt-5.4)
# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from functools import lru_cache

from flask import Flask, jsonify, request
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException

app = Flask(__name__)

ELASTICSEARCH_HOSTS = os.getenv("ELASTICSEARCH_HOSTS", "http://localhost:9200").split(",")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
SEARCH_TIMEOUT_SECONDS = float(os.getenv("SEARCH_TIMEOUT_SECONDS", "1.5"))
DEFAULT_PAGE_SIZE = int(os.getenv("DEFAULT_PAGE_SIZE", "20"))
MAX_PAGE_SIZE = int(os.getenv("MAX_PAGE_SIZE", "100"))


@lru_cache(maxsize=1)
def get_es_client():
    return Elasticsearch(
        ELASTICSEARCH_HOSTS,
        request_timeout=SEARCH_TIMEOUT_SECONDS,
        retry_on_timeout=True,
        max_retries=3,
    )


def parse_positive_int(value, default, minimum=1, maximum=None):
    try:
        parsed = int(value)
    except (TypeError, ValueError):
        return default
    if parsed < minimum:
        return default
    if maximum is not None and parsed > maximum:
        return maximum
    return parsed


@app.get("/api/search")
def search_products():
    query = (request.args.get("q") or "").strip()
    if not query:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    page = parse_positive_int(request.args.get("page"), default=1, minimum=1)
    size = parse_positive_int(request.args.get("size"), default=DEFAULT_PAGE_SIZE, minimum=1, maximum=MAX_PAGE_SIZE)
    from_ = (page - 1) * size

    es_query = {
        "from": from_,
        "size": size,
        "track_total_hits": False,
        "timeout": f"{int(SEARCH_TIMEOUT_SECONDS * 1000)}ms",
        "_source": True,
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": query,
                            "fields": [
                                "name^4",
                                "brand^2",
                                "category^2",
                                "description"
                            ],
                            "type": "best_fields",
                            "operator": "and",
                            "fuzziness": "AUTO"
                        }
                    },
                    {
                        "multi_match": {
                            "query": query,
                            "fields": [
                                "name.keyword^10",
                                "brand.keyword^5"
                            ],
                            "type": "phrase"
                        }
                    }
                ],
                "minimum_should_match": 1
            }
        },
        "sort": [
            "_score",
            {"popularity": {"order": "desc", "unmapped_type": "long"}}
        ]
    }

    try:
        es = get_es_client()
        response = es.search(index=ELASTICSEARCH_INDEX, body=es_query)
        hits = response.get("hits", {}).get("hits", [])

        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["id"] = hit.get("_id")
            source["score"] = hit.get("_score")
            products.append(source)

        total = response.get("hits", {}).get("total")
        if isinstance(total, dict):
            total_value = total.get("value")
        else:
            total_value = total

        return jsonify(
            {
                "query": query,
                "page": page,
                "size": size,
                "count": len(products),
                "total": total_value,
                "products": products,
            }
        ), 200

    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503
    except Exception:
        return jsonify({"error": "Internal server error"}), 500


if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")), threaded=True)